class MyCircularQueue:

    def __init__(self, k: int):
        self.size = k
        self.data = [0]*k
        self.front = -1
        self.rear = -1

    def enQueue(self, value: int) -> bool:
        if self.isFull():
            return False
        if self.isEmpty():
            self.front = 0
        self.rear = (self.rear + 1) % self.size
        self.data[self.rear] = value
        return True

    def deQueue(self) -> bool:
        if self.isEmpty():
            return False
        if self.front == self.rear:
            self.front = -1
            self.rear = -1
        else:
            self.front = (self.front + 1) % self.size
        return True

    def Front(self) -> int:
        if self.isEmpty():
            return -1
        return self.data[self.front]

    def Rear(self) -> int:
        if self.isEmpty():
            return -1
        return self.data[self.rear]

    def isEmpty(self) -> bool:
        return self.front == -1

    def isFull(self) -> bool:
        return (self.rear + 1) % self.size == self.front
```


    To implement a circular queue, we use an array of fixed size, and two pointers, `front` and `rear`, to keep track of the queue's current state:

- Initialize the queue by setting its size `k`, the array with size `k`, and both pointers to -1.
- Check whether the queue is empty by checking if the `front` pointer is -1. 
- Check whether the queue is full by checking whether the next available spot after the `rear` pointer is equal to the `front` pointer. Calculate it as `(rear + 1) % size == front`.
- To insert an element, move the `rear` pointer (modulo the queue size) and set the new value at `rear`.
- To delete an element, move the `front` pointer (modulo the queue size).
- To get the item at the front, return the value at the `front` pointer in the array.
- To get the item at the rear, return the value at the `rear` pointer in the array.

